fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let wetdry = required_f32(params, "wetdry").map_err(anyhow::Error::msg)?;
    let tempo1 = required_f32(params, "tempo1").map_err(anyhow::Error::msg)?;
    let type1 = required_f32(params, "type1").map_err(anyhow::Error::msg)?;
    let stdl1 = required_f32(params, "stdl1").map_err(anyhow::Error::msg)?;
    let tempo2 = required_f32(params, "tempo2").map_err(anyhow::Error::msg)?;
    let type2 = required_f32(params, "type2").map_err(anyhow::Error::msg)?;
    let stdl2 = required_f32(params, "stdl2").map_err(anyhow::Error::msg)?;
    let lmcr = required_f32(params, "lmcr").map_err(anyhow::Error::msg)?;
    let mmcr = required_f32(params, "mmcr").map_err(anyhow::Error::msg)?;
    let mhcr = required_f32(params, "mhcr").map_err(anyhow::Error::msg)?;
    let lb = required_f32(params, "lb").map_err(anyhow::Error::msg)?;
    let m1b = required_f32(params, "m1b").map_err(anyhow::Error::msg)?;
    let m2b = required_f32(params, "m2b").map_err(anyhow::Error::msg)?;
    let hb = required_f32(params, "hb").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_WETDRY, wetdry),
        (PORT_CTRL_TEMPO1, tempo1),
        (PORT_CTRL_TYPE1, type1),
        (PORT_CTRL_STDL1, stdl1),
        (PORT_CTRL_TEMPO2, tempo2),
        (PORT_CTRL_TYPE2, type2),
        (PORT_CTRL_STDL2, stdl2),
        (PORT_CTRL_LMCR, lmcr),
        (PORT_CTRL_MMCR, mmcr),
        (PORT_CTRL_MHCR, mhcr),
        (PORT_CTRL_LB, lb),
        (PORT_CTRL_M1B, m1b),
        (PORT_CTRL_M2B, m2b),
        (PORT_CTRL_HB, hb),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT_L, PORT_AUDIO_IN_INPUT_R], &[PORT_AUDIO_OUT_OUTPUT_L, PORT_AUDIO_OUT_OUTPUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

